        })();
    }

    public function fetch_ticker(string $symbol, $params = array()): PromiseInterface {
        return Async\async(function () use ($symbol, $params) {
            /**
             * fetches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific $market
             *
             * @see https://docs.trade.mudrex.com/docs
             *
             * @param {string} $symbol unified $symbol of the $market to fetch the ticker for
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
             */
            if ($this->markets === null) {
                Async\await($this->load_markets());
            }
            $market = $this->market($symbol);
            $request = array(
                'asset_id' => $market['id'],
                'is_symbol' => 1,
            );
            $response = Async\await($this->privateGetFuturesAssetId($this->extend($request, $params)));
            $data = $this->safe_dict($response, 'data', array());
            return $this->parse_ticker($data, $market);
        })();
    }

    public function fetch_tickers(?array $symbols = null, $params = array()): PromiseInterface {
        return Async\async(function () use ($symbols, $params) {
            /**
             * fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
             *
             * @see https://docs.trade.mudrex.com/docs
             *
             * @param {string[]} [$symbols] unified $symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a dictionary of [ticker structures](https://docs.ccxt.com/#/?id=ticker-structure)
             */
            if ($this->markets === null) {
                Async\await($this->load_markets());
            }
            $request = array();
            $response = Async\await($this->privateGetFutures($this->extend($request, $params)));
            $data = $this->safe_value($response, 'data', array());
            $rows = (gettype($data) === 'array' && array_keys($data) === array_keys(array_keys($data))) ? $data : $this->safe_list($data, 'items', array());
            $resultTickers = array();
            for ($i = 0; $i < count($rows); $i++) {
                $t = $rows[$i];
                $sym = $this->safe_string($t, 'symbol');
                if ($sym === null) {
                    continue;
                }
                $m = $this->safe_market($sym);
                $symbol = $m['symbol'];
                if ($symbols !== null && !$this->in_array($symbol, $symbols)) {
                    continue;
                }
                $resultTickers[$symbol] = $this->parse_ticker($t, $m);
            }
            return $this->filter_by_array_tickers($resultTickers, 'symbol', $symbols);
        })();
    }

    public function parse_ticker(array $ticker, ?array $market = null): array {
        $ms = $this->safe_string($ticker, 'symbol');
        $market = $this->safe_market($ms, $market);
        $symbol = $market['symbol'];
        $ts = $this->milliseconds();
        $pct = $this->safe_number($ticker, 'change_perc');
        return $this->safe_ticker(array(
            'symbol' => $symbol,
            'timestamp' => $ts,
            'datetime' => $this->iso8601($ts),
            'high' => null,
            'low' => null,
            'bid' => null,
            'bidVolume' => null,
            'ask' => null,
            'askVolume' => null,
            'vwap' => null,
            'open' => $this->safe_number($ticker, 'last_day_price'),
            'close' => $this->safe_number($ticker, 'price'),
            'last' => $this->safe_number($ticker, 'price'),
            'previousClose' => null,
            'change' => null,
            'percentage' => $pct,
            'average' => null,
            'baseVolume' => null,
            'quoteVolume' => $this->safe_number($ticker, 'volume'),
            'info' => $ticker,
        ), $market);
    }

    public function fetch_markets($params = array()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * retrieves $data on all markets for the exchange
             *
             * @see https://docs.trade.mudrex.com/docs
             *
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} an array of objects representing market $data
             */
            $aggregated = array();
            $offset = 0;
            $pageLimit = 100;
            $paging = true;
            while ($paging === true) {
                $q = $this->extend(array( 'limit' => $pageLimit, 'offset' => $offset ), $params);
                $response = Async\await($this->privateGetFutures($q));
                $data = $this->safe_value($response, 'data', array());
                $items = array();
                if (gettype($data) === 'array' && (gettype($data) !== 'array' || array_keys($data) !== array_keys(array_keys($data)))) {
                    $items = $this->safe_list($data, 'items', array());
                    if (strlen(!$items)) {
                        $items = $this->safe_list($data, 'results', array());
                    }
                    if (strlen(!$items) && (is_array($data) && array_key_exists('symbol', $data))) {
                        $items = array( $data );
                    }
                } else {
                    $items = $this->to_array($data);
                }
                if (strlen(!$items)) {
                    $paging = false;
                    break;
                }
                for ($i = 0; $i < count($items); $i++) {
                    $aggregated[] = $items[$i];
                }
                if (strlen($items) < $pageLimit) {
                    $paging = false;
                } else {
                    $offset .= $pageLimit;
                }
            }
            $result = array();
            for ($i = 0; $i < count($aggregated); $i++) {
                $result[] = $this->parse_market($aggregated[$i]);
            }
            return $result;
        })();
    }

    public function parse_market(array $asset): array {
        $ms = $this->safe_string($asset, 'symbol');
        $base = $ms;
        if ($ms !== null && str_ends_with($ms, 'USDT')) {
            $base = mb_substr($ms, 0, -4 - 0);
        }
        $quote = 'USDT';
        $settle = 'USDT';
        $symbol = null;
        if ($base !== null) {
            $symbol = $base . '/' . $quote . ':' . $settle;
        }
        $priceStep = $this->safe_string($asset, 'price_step', '0.01');
        $qtyStep = $this->safe_string($asset, 'quantity_step', '0.001');
        return $this->safe_market_structure(array(
            'id' => $ms,
            'lowercaseId' => null,
            'symbol' => $symbol,
            'base' => $base,
            'quote' => $quote,
            'settle' => $settle,
            'baseId' => $base,
            'quoteId' => 'USDT',
            'settleId' => 'USDT',
            'type' => 'swap',
            'spot' => false,
            'margin' => false,
            'swap' => true,
            'future' => false,
            'option' => false,
            'active' => true,
            'contract' => true,
            'linear' => true,
            'inverse' => false,
            'taker' => $this->safe_number($this->fees['trading'], 'taker'),
            'maker' => $this->safe_number($this->fees['trading'], 'maker'),
            'contractSize' => $this->safe_number($asset, 'contract_size', 1),
            'expiry' => null,
            'expiryDatetime' => null,
            'strike' => null,
            'optionType' => null,
            'precision' => array(
                'amount' => $this->parse_number($qtyStep),
                'price' => $this->parse_number($priceStep),
            ),
            'limits' => array(
                'amount' => array(
                    'min' => $this->safe_number($asset, 'min_contract'),
                    'max' => $this->safe_number($asset, 'max_contract'),
                ),
                'price' => array(
                    'min' => $this->safe_number($asset, 'min_price'),
                    'max' => $this->safe_number($asset, 'max_price'),
                ),
                'cost' => array(
                    'min' => $this->safe_number($asset, 'min_notional_value'),
                    'max' => null,
                ),
            ),
            'info' => $asset,
            'created' => null,
        ));
    }

    public function fetch_balance($params = array()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * query for balance and get the amount of funds available for trading or funds locked in orders
             *
             * @see https://docs.trade.mudrex.com/docs
             *
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->type] 'swap' (default) or 'spot' - which wallet balance to fetch
             * @param {string} [$params->trade_currency] the settlement $currency to query the balance for
             * @return {array} a [balance structure](https://docs.ccxt.com/#/?id=balance-structure)
             */
            if ($this->markets === null) {
                Async\await($this->load_markets());
            }
            $type = null;
            list($type, $params) = $this->handle_market_type_and_params('fetchBalance', null, $params, 'swap');
            $requested = $this->safe_string_n($params, array( 'trade_currency', 'tradeCurrency', 'currency' ));
            $params = $this->omit($params, array( 'trade_currency', 'tradeCurrency', 'currency' ));
            $request = array();
            $response = null;
            if ($type === 'spot') {
                if ($requested !== null) {
                    $request['currency'] = $requested;
                }
                $response = Async\await($this->privateGetWalletFunds($this->extend($request, $params)));
            } else {
                if ($requested !== null) {
                    $request['trade_currency'] = $requested;
                }
                $response = Async\await($this->privateGetFuturesFunds($this->extend($request, $params)));
            }
            $currency = $requested;
            if ($currency === null) {
                $currency = 'USDT';
            }
            if ($response === null) {
                throw new NullResponse($this->id . ' fetchBalance() returned empty response');
            }
            $response['currency'] = $currency;
            return $this->parse_balance($response);
        })();
    }

    public function parse_balance(mixed $response): array {
        $data = $this->safe_dict($response, 'data', array());
        $currency = $this->safe_string($response, 'currency', 'USDT');
        $timestamp = $this->milliseconds();
        $result = array(
            'info' => $response,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
        );
        $account = $this->account();
        $futuresBalance = $this->safe_string($data, 'balance');
        if ($futuresBalance !== null) {
            // futures wallet => balance is the free/available margin, locked_amount is used, safeBalance derives total
            $account['free'] = $futuresBalance;
            $account['used'] = $this->safe_string($data, 'locked_amount');
        } else {
            // spot wallet => total is the total, withdrawable is free, safeBalance derives used
            $account['total'] = $this->safe_string($data, 'total');
            $account['free'] = $this->safe_string($data, 'withdrawable');
        }
        $result[$currency] = $account;
        return $this->safe_balance($result);
    }

